python3 -c "
import json
import os
# Check HF cache for model config to verify size
for cache_dir in ['/root/.cache/huggingface/hub', os.path.expanduser('~/.cache/huggingface/hub')]:
    if os.path.exists(cache_dir):
        for d in os.listdir(cache_dir):
            if 'gemma' in d.lower():
                print('Found:', os.path.join(cache_dir, d))
                # Try to read config
                cfg_path = os.path.join(cache_dir, d, 'snapshots')
                if os.path.exists(cfg_path):
                    for snap in os.listdir(cfg_path):
                        snap_cfg = os.path.join(cfg_path, snap, 'config.json')
                        if os.path.exists(snap_cfg):
                            with open(snap_cfg) as f:
                                cfg = json.load(f)
                            print('  config keys:', list(cfg.keys())[:20])
                            for k in ['hidden_size', 'num_hidden_layers', 'num_attention_heads', 'intermediate_size', 'vocab_size', 'torch_dtype']:
                                if k in cfg:
                                    print(f'    {k}: {cfg[k]}')
"
